class Solution(object):
    def maximumValueSum(self, board):
        """
        :type board: List[List[int]]
        :rtype: int
        """
        m, n = len(board), len(board[0])

        # Find top 3 values in each row
        row_tops = []
        for i in range(m):
            tops = sorted(enumerate(board[i]), key=lambda x: -x[1])[:3]
            row_tops.append(tops)

        max_sum = float('-inf')

        # Try all combinations of 3 different rows
        for i in range(m):
            for j in range(i + 1, m):
                for k in range(j + 1, m):
                    # Try all combinations of columns from top 3 of each row
                    for col_i, val_i in row_tops[i]:
                        for col_j, val_j in row_tops[j]:
                            for col_k, val_k in row_tops[k]:
                                # Check if columns are different
                                if col_i != col_j and col_j != col_k and col_i != col_k:
                                    max_sum = max(max_sum, val_i + val_j + val_k)

        return max_sum
